class Solution:
    def countDistinct(self, nums, k, p):
        n = len(nums)
        seen = set()
        for i in range(n):
            for j in range(i, n):
                sub = tuple(nums[i:j + 1])
                cnt = sum(1 for x in sub if x % p == 0)
                if cnt <= k:
                    seen.add(sub)
        return len(seen)

