class Solution:
    def countDistinct(self, nums, k, p):
        n = len(nums)
        seen = set()
        for i in range(n):
            cnt = 0
            window = []
            for j in range(i, n):
                if nums[j] % p == 0:
                    cnt += 1
                if cnt > k:
                    break
                window.append(nums[j])
                seen.add(tuple(window))
        return len(seen)

