var countDistinct = function(nums, k, p) {
    const n = nums.length;
    const seen = new Set();
    for (let i = 0; i < n; i++) {
        let cnt = 0;
        const window = [];
        for (let j = i; j < n; j++) {
            if (nums[j] % p === 0) cnt++;
            if (cnt > k) break;
            window.push(nums[j]);
            seen.add(window.join(','));
        }
    }
    return seen.size;
};
